<template>
  <div class="contact">
    <el-row type="flex"
class="row-bg" justify="center">
      <el-col :span="20">
        <h2>{{ $t(`checkout.title`) }}</h2>
        <el-form ref="form" method="POST" :model="form">
          <el-form-item class="antispam-field">
            <el-input
              v-model="form.website"
              name="website"
              autocomplete="off"
              tabindex="-1"
            />
          </el-form-item>
          <el-form-item>
            <el-input
              v-model="form.name"
              name="name"
              :placeholder="$t(`contact.form.name`)"
              required
            />
          </el-form-item>
          <el-form-item>
            <el-input
              v-model="form.phone"
              name="phone"
              :placeholder="$t(`contact.form.phone`)"
              required
            />
          </el-form-item>
          <el-form-item>
            <el-input
              v-model="form.email"
              name="email"
              :placeholder="$t(`contact.form.email`)"
              required
            />
          </el-form-item>
          <el-form-item>
            <el-input
              v-model="form.country"
              name="country"
              :placeholder="$t(`checkout.form.country`)"
            />
          </el-form-item>

          <el-row v-for="product in products" type="flex" :key="product.id">
            <el-col :span="9">
              <img
                :src="require(`@/assets/img/${product.images[0]}`)"
                class="image"
              />
            </el-col>
            <el-col :span="15">
              <div class="productListInCart">
                <h2>{{ product.title }}</h2>
                <p>${{ product.price }} x {{ product.quantity }}</p>
                <div v-if="product.totalPrice">
                  <h5>Additional config:</h5>
                  <ul class="product-configurator">
                    <li v-for="check in product.checkList"
:key="check">
                      {{ $t('shop.product.products.1.configurator.' + check) }}:
                      + ${{ product.configurator[check] }}
                    </li>
                  </ul>
                  <p>
                    {{ $t('shop.cart.positionTotal') }}:
                    <b>${{ product.totalPrice * product.quantity }}</b>
                  </p>
                </div>
                <div v-else>
                  <p>
                    {{ $t('shop.cart.positionTotal') }}:
                    <b>${{ product.price * product.quantity }}</b>
                  </p>
                </div>
              </div>
            </el-col>
          </el-row>

          <p>
            {{ $t('shop.cart.total') }}: <b>${{ total }}</b>
          </p>
          <el-form-item>
            <el-button type="primary"
@click="submitForm()">
              {{ $t('checkout.form.submit') }}
            </el-button>
          </el-form-item>
        </el-form>
        <div v-if="processing" class="processing-message">
          <div
            v-loading="processing"
            element-loading-text="Sending..."
            customClass="loading"
          />
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import axios from 'axios'
import { mapGetters, mapState } from 'vuex'

export default {
  data() {
    return {
      form: {
        name: '',
        phone: '',
        email: '',
        country: '',
        // Поле пастка для ботів
        website: '',
      },
      processing: false,
      startTime: 0, // Для відстеження часу заповнення
    }
  },
  computed: {
    ...mapState({
      checkoutStatus: state => state.cart.checkoutStatus,
    }),
    ...mapGetters('cart', {
      products: 'cartProducts',
      total: 'cartTotalPrice',
    }),
  },
  mounted() {
    // Фіксуємо час, коли користувач відкрив сторінку
    this.startTime = Date.now()
  },
  methods: {
    async submitForm() {
      // 1. Валідація полів
      if (
        !this.form.name ||
        !this.form.phone ||
        !this.form.email ||
        !this.form.country
      ) {
        this.$notify.error({
          title: this.$t('notifications.errorTitle'),
          message: this.$t('notifications.fillAllFields'),
          offset: 150,
          duration: 4500,
        })
        return
      }

      this.processing = true

      // 2. Отримання IP адреси клієнта
      let clientIp = 'Unknown'
      try {
        // Безкоштовний API для отримання IP
        const ipResponse = await axios.get('https://api.ipify.org?format=json')
        if (ipResponse.data && ipResponse.data.ip) {
          clientIp = ipResponse.data.ip
        }
      } catch (e) {
        console.warn('Failed to get IP address, continuing without it.')
      }

      // 3. Формування даних для відправки
      const orderData = {
        name: this.form.name,
        phone: this.form.phone,
        email: this.form.email,
        country: this.form.country,

        // --- ДАНІ ДЛЯ ЗАХИСТУ ТА АНАЛІТИКИ ---
        ip: clientIp,
        honeypot: this.form.website, // Якщо заповнено - це бот
        timeTaken: Date.now() - this.startTime, // Час заповнення форми в мс
        // -------------------------------------

        total: this.total,
        products: this.products.map(product => ({
          title: product.title,
          price: product.price,
          quantity: product.quantity,
        })),
      }

      // Адреса вашого Google Apps Script
      // УВАГА: Якщо ви зробили новий деплой, перевірте чи не змінився URL!
      const GOOGLE_SCRIPT_URL =
        'https://script.google.com/macros/s/AKfycbzUf9vTcGVULDw2wtfpAo3Y4Ektw2hC3aPZ5cuysYbAs7oM8mW0_PGkXX9bNfz3GdwG/exec'

      axios
        .post(GOOGLE_SCRIPT_URL, JSON.stringify(orderData), {
          headers: {
            'Content-Type': 'text/plain;charset=utf-8',
          },
        })
        .then(response => {
          this.processing = false

          if (response.data && response.data.status === 'success') {
            this.$notify({
              title: this.$t('notifications.succesfullOrderTitle'),
              message: this.$t('notifications.succesfullOrder'),
              type: 'success',
              offset: 100,
              duration: 4500,
            })
            this.$store.dispatch('cart/clearCart')
            this.$router.push('/shop')
          } else {
            this.$notify.error({
              title: this.$t('notifications.errorTitle'),
              message:
                (response.data && response.data.message) ||
                'An error occurred while processing your order.',
              offset: 100,
              duration: 4500,
            })
          }
        })
        .catch(error => {
          console.error('Submission error:', error)
          this.processing = false
          this.$notify.error({
            title: this.$t('notifications.errorTitle'),
            message: 'Failed to send the order. Please try again.',
            offset: 100,
            duration: 4500,
          })
        })
    },
  },
}
</script>

<style lang="scss" scoped>
.image {
  max-height: 200px;
  display: block;
  margin-left: auto;
  margin-right: auto;
  max-width: 50%;
}
ul {
  margin-top: 0;
  padding: 0 0 0 15px;
}
li {
  list-style-type: none;
}
h5 {
  margin-bottom: 5px;
}

/* Стиль для прихованого поля (Honeypot) */
/* Воно має бути в DOM, але невидиме для користувача */
.antispam-field {
  position: absolute;
  left: -9999px;
  opacity: 0;
  z-index: -1;
  height: 0;
  width: 0;
  overflow: hidden;
}
</style>
